import dayjs from 'dayjs';
import { DateStringValue } from '../../../types';
import { DayProps } from '../../Day/Day';
import { isAfterMinDate } from '../is-after-min-date/is-after-min-date';
import { isBeforeMaxDate } from '../is-before-max-date/is-before-max-date';
import { isSameMonth } from '../is-same-month/is-same-month';

interface GetDateInTabOrderInput {
  dates: DateStringValue[][];
  minDate: DateStringValue | undefined;
  maxDate: DateStringValue | undefined;
  getDayProps: ((date: DateStringValue) => Partial<DayProps>) | undefined;
  excludeDate: ((date: DateStringValue) => boolean) | undefined;
  hideOutsideDates: boolean | undefined;
  month: DateStringValue;
}

export function getDateInTabOrder({
  dates,
  minDate,
  maxDate,
  getDayProps,
  excludeDate,
  hideOutsideDates,
  month,
}: GetDateInTabOrderInput) {
  const enabledDates = dates
    .flat()
    .filter(
      (date) =>
        isBeforeMaxDate(date, maxDate) &&
        isAfterMinDate(date, minDate) &&
        !excludeDate?.(date) &&
        !getDayProps?.(date)?.disabled &&
        (!hideOutsideDates || isSameMonth(date, month))
    );

  const selectedDate = enabledDates.find((date) => getDayProps?.(date)?.selected);

  if (selectedDate) {
    return selectedDate;
  }

  const currentDate = enabledDates.find((date) => dayjs().isSame(date, 'date'));

  if (currentDate) {
    return currentDate;
  }

  return enabledDates[0];
}

import dayjs from 'dayjs';
import { DateStringValue, DayOfWeek } from '../../../types';
import { getEndOfWeek } from '../get-end-of-week/get-end-of-week';
import { getStartOfWeek } from '../get-start-of-week/get-start-of-week';

interface GetMonthDaysInput {
  month: DateStringValue;
  firstDayOfWeek: DayOfWeek | undefined;
  consistentWeeks: boolean | undefined;
}

export function getMonthDays({
  month,
  firstDayOfWeek = 1,
  consistentWeeks,
}: GetMonthDaysInput): DateStringValue[][] {
  const day = dayjs(month).subtract(dayjs(month).date() - 1, 'day');
  const start = dayjs(day.format('YYYY-M-D'));
  const startOfMonth = start.format('YYYY-MM-DD');
  const endOfMonth = start.add(+start.daysInMonth() - 1, 'day').format('YYYY-MM-DD');
  const endDate = getEndOfWeek(endOfMonth, firstDayOfWeek);
  const weeks: DateStringValue[][] = [];

  let date = dayjs(getStartOfWeek(startOfMonth, firstDayOfWeek));

  while (dayjs(date).isBefore(endDate, 'day')) {
    const days: DateStringValue[] = [];

    for (let i = 0; i < 7; i += 1) {
      days.push(date.format('YYYY-MM-DD'));
      date = date.add(1, 'day');
    }

    weeks.push(days);
  }

  if (consistentWeeks && weeks.length < 6) {
    const lastWeek = weeks[weeks.length - 1];
    const lastDay = lastWeek[lastWeek.length - 1];
    let nextDay = dayjs(lastDay).add(1, 'day');

    while (weeks.length < 6) {
      const days: DateStringValue[] = [];

      for (let i = 0; i < 7; i += 1) {
        days.push(nextDay.format('YYYY-MM-DD'));
        nextDay = nextDay.add(1, 'day');
      }

      weeks.push(days);
    }
  }

  return weeks;
}

